import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { coursesAPI } from '../../services/api';
import './Courses.css';

const Courses = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('all');
  const { user } = useAuth();

  const courseCategories = [
    'all',
    'technology',
    'business',
    'design',
    'data-science',
    'marketing',
    'personal-development'
  ];

  useEffect(() => {
    fetchCourses();
  }, []);

  const fetchCourses = async () => {
    setLoading(true);
    try {
      // Mock course data - replace with actual API call
      const mockCourses = [
        {
          id: 1,
          title: 'Complete Web Development Bootcamp',
          platform: 'Udemy',
          category: 'technology',
          duration: '40 hours',
          level: 'Beginner to Advanced',
          rating: 4.7,
          students: 1500000,
          price: '$89.99',
          originalPrice: '$189.99',
          image: 'https://img-c.udemycdn.com/course/240x135/1565838_e54e_16.jpg',
          link: 'https://www.udemy.com/course/the-complete-web-development-bootcamp/',
          skills: ['HTML', 'CSS', 'JavaScript', 'React', 'Node.js', 'MongoDB']
        },
        {
          id: 2,
          title: 'Machine Learning Specialization',
          platform: 'Coursera',
          category: 'data-science',
          duration: '3 months',
          level: 'Intermediate',
          rating: 4.8,
          students: 500000,
          price: 'Free',
          originalPrice: '$49/month',
          image: 'https://img-c.udemycdn.com/course/240x135/950390_270f_3.jpg',
          link: 'https://www.coursera.org/specializations/machine-learning-introduction',
          skills: ['Python', 'Machine Learning', 'TensorFlow', 'Data Analysis']
        },
        {
          id: 3,
          title: 'UI/UX Design Specialization',
          platform: 'Coursera',
          category: 'design',
          duration: '6 months',
          level: 'Beginner',
          rating: 4.6,
          students: 300000,
          price: 'Free',
          originalPrice: '$49/month',
          image: 'https://img-c.udemycdn.com/course/240x135/1650610_6654_3.jpg',
          link: 'https://www.coursera.org/specializations/ui-ux-design',
          skills: ['Figma', 'User Research', 'Wireframing', 'Prototyping']
        },
        {
          id: 4,
          title: 'Digital Marketing Mastery',
          platform: 'Google Digital Garage',
          category: 'marketing',
          duration: '40 hours',
          level: 'Beginner',
          rating: 4.5,
          students: 800000,
          price: 'Free',
          originalPrice: 'Free',
          image: 'https://img-c.udemycdn.com/course/240x135/914296_3670_8.jpg',
          link: 'https://learndigital.withgoogle.com/digitalgarage',
          skills: ['SEO', 'Social Media', 'Google Analytics', 'Content Marketing']
        }
      ];
      
      setCourses(mockCourses);
    } catch (error) {
      console.error('Error fetching courses:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredCourses = selectedCategory === 'all' 
    ? courses 
    : courses.filter(course => course.category === selectedCategory);

  const enrollCourse = (courseLink) => {
    window.open(courseLink, '_blank');
  };

  if (!user) {
    return (
      <div className="courses-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to explore courses.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="courses-container">
        <div className="container">
          <div className="loading">Loading courses...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="courses-container">
      <div className="container">
        <div className="courses-header">
          <h1>📚 Recommended Courses</h1>
          <p>Curated learning paths based on your career interests and skills</p>
        </div>

        <div className="courses-filters">
          <h3>Filter by Category:</h3>
          <div className="filter-buttons">
            {courseCategories.map(category => (
              <button
                key={category}
                className={`filter-btn ${selectedCategory === category ? 'active' : ''}`}
                onClick={() => setSelectedCategory(category)}
              >
                {category.charAt(0).toUpperCase() + category.slice(1).replace('-', ' ')}
              </button>
            ))}
          </div>
        </div>

        <div className="courses-grid">
          {filteredCourses.map(course => (
            <div key={course.id} className="course-card">
              <div className="course-image">
                <img src={course.image} alt={course.title} />
                <span className="platform-badge">{course.platform}</span>
              </div>
              
              <div className="course-content">
                <h3>{course.title}</h3>
                
                <div className="course-meta">
                  <span className="duration">⏱️ {course.duration}</span>
                  <span className="level">📊 {course.level}</span>
                  <span className="rating">⭐ {course.rating} ({course.students.toLocaleString()})</span>
                </div>

                <div className="course-skills">
                  <strong>Skills you'll learn:</strong>
                  <div className="skills-tags">
                    {course.skills.map((skill, index) => (
                      <span key={index} className="skill-tag">{skill}</span>
                    ))}
                  </div>
                </div>

                <div className="course-pricing">
                  <span className="price">{course.price}</span>
                  {course.originalPrice && course.price !== course.originalPrice && (
                    <span className="original-price">{course.originalPrice}</span>
                  )}
                </div>

                <button 
                  onClick={() => enrollCourse(course.link)}
                  className="btn btn-primary enroll-btn"
                >
                  Enroll Now on {course.platform}
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Courses;
